submitbug.file.description:
需要提供一个 JSON 配置文件，用于通过 CLI 提交 Bug。内容示例如下：
			{
				"title": "在这里填写 Bug 标题",
				// Bug 标题，简要描述问题

				"product": 6,
				// 产品类型：4 = HBuilderX，6 = uni-app x

				"step": "在这里填写问题复现步骤",
				// 问题复现步骤，越详细越有助于定位问题

				"wantResult": "在这里填写期望的正确结果",
				// 期望的正确结果描述

				"module": "填写模块 id",
				// 问题所属模块，填写模块 id，可通过 --moduleList 获取可用值

				"attachmentPath": "填写一个文件夹路径用于存放附件",
				// 附件目录路径（HBuilderX 生效），填写一个文件夹即可

				"runLog": "填写一个文件路径用于运行日志",
				// 运行日志文件路径，必须指向一个文件

				"phoneOsPlatform": [1, 2, 3],
				// 运行平台（仅 uni-app x 生效）：
				// 1 = Android，2 = iOS，3 = Web，4 = 微信，5 = 鸿蒙

				"phoneOsVersion": "填写手机系统版本",
				// 手机系统版本（uni-app x 生效）

				"phoneBrand": "填写手机品牌",
				// 手机品牌（uni-app x 生效）

				"phoneModel": "填写手机型号",
				// 手机型号（uni-app x 生效）

				"isVaporMode": false,
				// 是否启用蒸汽模式（uni-app x 生效）

				"sampleProjectGit": "填写示例项目 Git 地址",
				// 示例项目的 Git 地址（uni-app x 生效）

				"sampleProject": "填写本地示例项目路径",
				// 本地示例项目路径（uni-app x 生效）

				"projectPublic": true,
				// 本地项目是否公开（uni-app x 生效）

				"picPath": []
				// 截图路径数组（uni-app x 生效）

			}
